This might need some more methods to enable round-trip of the binary blobs... perhaps inspired by `VarBinarySerializerMax`'s `write*` methods?

```
class VarBinarySerializerMax(VarBinarySerializer):
    def __init__(self):
        super(VarBinarySerializerMax, self).__init__(0)

    def __repr__(self):
        return 'VarBinaryMax()'

    def write_info(self, w):
        w.put_usmallint(tds_base.PLP_MARKER)

    def write(self, w, val):
        if val is None:
            w.put_uint8(tds_base.PLP_NULL)
        else:
            w.put_uint8(len(val))
            if val:
                w.put_uint(len(val))
                w.write(val)
            w.put_uint(0)

    def read(self, r):
        r = PlpReader(r)
        if r.is_null():
            return None
        return b''.join(r.chunks())
```

I'm working on this. However, the whole `cli()` needs to be refactored to support it nicely. So far, I have the custom click option to support file globbing:

```python
import pathlib2 as pathlib

class TemplateFile(click.File):

    def __init__(self, mode='r', encoding=None, errors='strict', lazy=None,
                 atomic=False):
        super().__init__(mode, encoding, errors, lazy, atomic)

    def glob(self, pattern, param, ctx):
        files = []
        for p in pathlib.Path('.').glob(pattern):
            if p.is_dir():
                continue # skip directories
            p = super().convert(str(p), param, ctx)
            files.append(p)
        return files

    def convert(self, value, param, ctx):
        try:
            return super().convert(value, param, ctx)
        except click.exceptions.BadParameter:
            if '*' in value:
                return self.glob(value, param, ctx)
            else:
                raise
```

