```
public class SucuriCloudProxyHelper {
    public static boolean isProtected(String js) {
        return js.contains("sucuri");
    }

    public static String solve(String originalJs) {
        String transformedJs = transformJs(originalJs);
        Duktape duktape = Duktape.create();
        duktape.evaluate(transformedJs);
        SucuriCloudProxy sucuriCloudProxy = duktape.proxy("SucuriCloudProxy", SucuriCloudProxy.class);
        String solveResult = sucuriCloudProxy.solve();
        duktape.close();
        return solveResult;
    }

    private static String transformJs(String originalJs) {
        return "var SucuriCloudProxy = {\n" +
                "\tsolve: function() {\n" +
                "\t\tdocument = {};\n" +
                "\t\tlocation = {reload: function(){/*Empty method of location.reload()*/}};\n" +
                originalJs +
                ";\n" +
                "\t\treturn document.cookie.toString();\n" +
                "\t}\n" +
                "};";
    }

    private interface SucuriCloudProxy {
        String solve();
    }
}
```

